import Dashboard from '../assests/admin/admin/Dashboard';
import Profile from '../assests/admin/admin/Profile';
import Category from '../assests/admin/admin/category/Category';
import ViewCategory from '../assests/admin/admin/category/ViewCategory';
import EditCategory from '../assests/admin/admin/category/EditCategory';
// Import product
import AddProduct from '../assests/admin/admin/Product/AddProduct';
import EditProduct from '../assests/admin/admin/Product/EditProduct';
import ViewProduct from '../assests/admin/admin/Product/ViewProduct';

// Define routes for the admin panel

const routes = [
    // Paths are now relative to the parent "/admin" route.
    // The `exact` prop is no longer needed in React Router v6.
    { path: 'dashboard', name: 'Dashboard', component: Dashboard },
    { path: 'category', name: 'Category', component: Category },
    { path: 'view', name: 'ViewCategory', component: ViewCategory },
    { path: 'edit/:id', name: 'EditCategory', component: EditCategory },

    {/* Fallback route for undefined paths */ },
    { path: 'add-product', name: 'AddProduct', component: AddProduct },
    { path: 'edit-product/:id', name: 'EditProduct', component: EditProduct },
    { path: 'view-product', name: 'ViewProduct', component: ViewProduct },



    { path: 'profile', name: 'Profile', component: Profile },
];

export default routes;
